		reply = wrap_onionreply(tmpctx, &ss[i], reply);
		printf("obfuscated_packet %s\n", tal_hex(tmpctx, reply->contents));
		assert(memcmp(reply->contents, intermediates[i], tal_count(reply->contents)) == 0);
